import time

def cache_result(func):
    cache = {}
    def wrapper(*args):
        if args in cache:
            return cache[args]
        result = func(*args)
        cache[args] = result
        return result
    return wrapper

@cache_result
def slow_operation(n):
    time.sleep(1)
    return n * 2

# Bug: cache grows indefinitely
slow_operation(1)  # Cached
slow_operation(2)  # Cached
# ... 1000 more calls later, cache has 1002 entries
```

